class UnionFind {
    int[] parent;
    int components;

    UnionFind(int size) {
        parent = new int[size];
        components = size;
        for (int i = 0; i < size; ++i) {
            parent[i] = i;
        }
    }

    int find(int x) {
        if (x != parent[x])
            parent[x] = find(parent[x]);
        return parent[x];
    }

    boolean unite(int x, int y) {
        int rootX = find(x);
        int rootY = find(y);
        if (rootX != rootY) {
            parent[rootX] = rootY;
            components--;
            return true;
        }
        return false;
    }
}

public int maxNumEdgesToRemove(int n, int[][] edges) {
    UnionFind ufA = new UnionFind(n + 1);
    UnionFind ufB = new UnionFind(n + 1);
    int common_edges = 0;

    for (int[] edge : edges) {
        if (edge[0] == 3) {
            if (ufA.unite(edge[1], edge[2])) {
                ufB.unite(edge[1], edge[2]);
                common_edges++;
            }
        }
    }

    int removed_edges = 0;
    for (int[] edge : edges) {
        UnionFind uf = (edge[0] == 1) ? ufA : (edge[0] == 2) ? ufB : null;
        if (uf != null && !uf.unite(edge[1], edge[2])) {
            removed_edges++;
        }
    }

    if (ufA.components != 2 || ufB.components != 2)
        return -1;
    return removed_edges - common_edges;
}
